ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_FLAECHEN_STELLPLATZ" CHECK (FLAECHEN_STELLPLATZ in ('F', 'T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LGR_ABC" CHECK (ABC in (1, 2, 3)) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LGR_GESPERRT" CHECK (GESPERRT in('F','G','N', 'M', 'X')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LGR_TYP" CHECK (LGR_TYP in ('SAT1','SAT_EPL1', 'SAT_EPL2', 'EPL1', 'KANAL1', 'KANBKL1', 'BKL1', 'REG_FACH1', 'SEG1', 'SEG_DUEDO1', 'DURCHL1',  'PP_EPL1', 'STAP_FLAE1', 'STAP_FLAE2')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LGR_UML_ERLAUBT" CHECK (UML_ERLAUBT in ('T','F','R')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LGR_VERWENDUNG" CHECK (LGR_VERWENDUNG  in('Lager', 'WE', 'WA', 'EP', 'Puffer', 'WEP', 'LagerP')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LGR_WAREN_TYPEN_CFG" CHECK (WAREN_TYPEN_CFG like  ('%FW;%') or  WAREN_TYPEN_CFG like ('%RW;%') or WAREN_TYPEN_CFG like  ('%HW;%')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LGR_WA_MENGE_UEBERLIEF" CHECK (WA_MENGE_UEBERLIEF in ('F','T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LVS_LAGER_UML_ERLAUBT" CHECK (uml_erlaubt in ('T', 'F', 'R')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_LVS_LGR_WA_TYP" CHECK (WA_TYP in ('LDPR', 'LDPO','BDEPUSH','BDEICEPUSH') or WA_TYP is NULL) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "CHECK_RES_RES_STRING_STATISCH" CHECK (RES_RES_STRING_STATISCH in ('F', 'T')) ENABLE;
ALTER TABLE "DIRKSPZM32"."LVS_LGR" ADD CONSTRAINT "PK_LVS_LGR" PRIMARY KEY ("LGR_PLATZ")
  USING INDEX  ENABLE;


