YPE>\n            <SCALE>0</SCALE>\n         </COL_LIST_ITEM>\n         <COL_LIST_ITEM>\n            <NAME>EINL_ORT_DEFAULT_LISTE</NAME>\n            <DATATYPE>VARCHAR2</DATATYPE>\n            <LENGTH>100</LENGTH>\n            <CHAR_SEMANTICS></CHAR_SEMANTICS>\n            <COLLATE_NAME>USING_NLS_COMP</COLLATE_NAME>\n         </COL_LIST_ITEM>\n      </COL_LIST>\n      <CHECK_CONSTRAINT_LIST>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_FLAECHEN_STELLPLATZ</NAME>\n            <CONDITION>FLAECHEN_STELLPLATZ in ('F', 'T')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LGR_ABC</NAME>\n            <CONDITION>ABC in (1, 2, 3)</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LGR_GESPERRT</NAME>\n            <CONDITION>GESPERRT in('F','G','N', 'M', 'X')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LGR_TYP</NAME>\n            <CONDITION>LGR_TYP in ('SAT1','SAT_EPL1', 'SAT_EPL2', 'EPL1', 'KANAL1', 'KANBKL1', 'BKL1', 'REG_FACH1', 'SEG1', 'SEG_DUEDO1', 'DURCHL1',  'PP_EPL1', 'STAP_FLAE1', 'STAP_FLAE2')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LGR_UML_ERLAUBT</NAME>\n            <CONDITION>UML_ERLAUBT in ('T','F','R')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LGR_VERWENDUNG</NAME>\n            <CONDITION>LGR_VERWENDUNG  in('Lager', 'WE', 'WA', 'EP', 'Puffer', 'WEP', 'LagerP')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LGR_WA_MENGE_UEBERLIEF</NAME>\n            <CONDITION>WA_MENGE_UEBERLIEF in ('F','T')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LGR_WAREN_TYPEN_CFG</NAME>\n            <CONDITION>WAREN_TYPEN_CFG like  ('%FW;%') or  WAREN_TYPEN_CFG like ('%RW;%') or WAREN_TYPEN_CFG like  ('%HW;%')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LVS_LAGER_UML_ERLAUBT</NAME>\n            <CONDITION>uml_erlaubt in ('T', 'F', 'R')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_LVS_LGR_WA_TYP</NAME>\n            <CONDITION>WA_TYP in ('LDPR', 'LDPO','BDEPUSH','BDEICEPUSH') or WA_TYP is NULL</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n         <CHECK_CONSTRAINT_LIST_ITEM>\n            <NAME>CHECK_RES_RES_STRING_STATISCH</NAME>\n            <CONDITION>RES_RES_STRING_STATISCH in ('F', 'T')</CONDITION>\n         </CHECK_CONSTRAINT_LIST_ITEM>\n      </CHECK_CONSTRAINT_LIST>\n      <PRIMARY_KEY_CONSTRAINT_LIST>\n         <PRIMARY_KEY_CONSTRAINT_LIST_ITEM>\n            <NAME>PK_LVS_LGR</NAME>\n            <COL_LIST>\n               <COL_LIST_ITEM>\n                  <NAME>LGR_PLATZ</NAME>\n               </COL_LIST_ITEM>\n            </COL_LIST>\n            <USING_INDEX></USING_INDEX>\n         </PRIMARY_KEY_CONSTRAINT_LIST_ITEM>\n      </PRIMARY_KEY_CONSTRAINT_LIST>\n      <DEFAULT_COLLATION>USING_NLS_COMP</DEFAULT_COLLATION>\n      <PHYSICAL_PROPERTIES>\n         <HEAP_TABLE></HEAP_TABLE>\n      </PHYSICAL_PROPERTIES>\n   </RELATIONAL_TABLE>\n</TABLE>"}